package com.example.systemoptimization

import android.app.Service
import android.content.Intent
import android.os.IBinder
import android.util.Log
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.launch

class MaintenanceService : Service() {

    companion object {
        const val ACTION_SYNC_DATA = "com.example.systemoptimization.action.SYNC_DATA"
        const val ACTION_CLEANUP = "com.example.systemoptimization.action.CLEANUP"

        const val EXTRA_TARGET = "extra_target"
        const val EXTRA_FORCE = "extra_force"
        const val EXTRA_SCOPE = "extra_scope"

        private const val TAG = "MaintenanceService"
    }

    private val serviceScope = CoroutineScope(SupervisorJob() + Dispatchers.IO)

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        val action = intent?.action
        val target = intent?.getStringExtra(EXTRA_TARGET).orEmpty()
        val force = intent?.getBooleanExtra(EXTRA_FORCE, false) ?: false
        val scope = intent?.getStringExtra(EXTRA_SCOPE).orEmpty()

        serviceScope.launch {
            when (action) {
                ACTION_SYNC_DATA -> performDataSync(target, force, scope)
                ACTION_CLEANUP -> performCleanup(target, force, scope)
                else -> Log.w(TAG, "Unknown or missing action: $action")
            }
            stopSelf(startId)
        }

        return START_NOT_STICKY
    }

    private fun performDataSync(target: String, force: Boolean, scope: String) {
        Log.i(TAG, "Starting data sync. target=$target, force=$force, scope=$scope")
        try {
            Thread.sleep(1500)
            Log.i(TAG, "Data sync completed. target=$target")
        } catch (e: Exception) {
            Log.e(TAG, "Data sync failed", e)
        }
    }

    private fun performCleanup(target: String, force: Boolean, scope: String) {
        Log.i(TAG, "Starting cleanup. target=$target, force=$force, scope=$scope")
        try {
            Thread.sleep(1200)
            Log.i(TAG, "Cleanup completed. target=$target")
        } catch (e: Exception) {
            Log.e(TAG, "Cleanup failed", e)
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        serviceScope.coroutineContext.cancelChildren()
    }
}

